const payload = $('子流程入口-sora').item.json.body || {};
const imageResponse = $('获取图片链接').item.json || {};
const imageUrl = imageResponse?.body?.data?.tmp_download_urls?.[0]?.tmp_download_url;

if (!imageUrl) {
  throw new Error('获取图片链接节点没有拿到 tmp_download_url');
}

const requestBody = {
  model: 'sora-2-all',
  input: {
    prompt: payload.prompt || '',
    image_urls: [imageUrl],
    aspect_ratio: payload.aspect_ratio, // 这里允许 9:16，后面清洗节点会转 portrait/landscape
    n_frames: payload.n_frames || '15',
    remove_watermark: true
  }
};

return {
  json: {
    requestBody,

    // 父表上下文（原有）
    record_id: payload.record_id,
    app_token: payload.app_token,
    table_id: payload.table_id,
    tenant_access_token: payload.tenant_access_token,
    workflow_id_for_credits: payload.workflow_id_for_credits,
    api_key: payload.api_key,

    // ✅ 子表定位（新增：必须透传到清洗提示词，才能进入 callbackUrl）
    out_app_token: payload.out_app_token,
    out_table_id: payload.out_table_id,

    // （可选）你以后做批次/占位行会用到，先透传不亏
    batch_id: payload.batch_id,
    child_record_id: payload.child_record_id
  }
};

/**
 * 准备视频参数-云雾（/v1/video/create）
 * - 兼容：图生（image_1_token）/ 文生
 * - model：严格透传入参 payload.model（不替换）
 * - aspect_ratio：兼容 portrait/landscape/9:16/16:9，最终输出 9:16 或 16:9
 * - 避免引用未执行节点：从上游 item.json 取 imageUrl，不强依赖某个固定节点
 */

const payload = $('子流程入口-sora').first().json.body || {};

const safe = (v) => String(v ?? '').replace(/\r?\n/g, ' ').trim();

function cleanPrompt(raw) {
  let p = raw ?? '';
  if (Array.isArray(p)) p = p.join(' ');
  if (typeof p !== 'string') p = String(p);
  p = p.replace(/\r?\n+/g, ' ').replace(/\s{2,}/g, ' ').trim();
  const negIdx = p.indexOf('Negative prompt:');
  if (negIdx >= 0) p = p.slice(0, negIdx).trim();
  return p;
}

function normAspect(v) {
  const s = String(v ?? '').trim().toLowerCase();
  if (!s) return '9:16';
  if (s === 'portrait') return '9:16';
  if (s === 'landscape') return '16:9';
  if (s === '9:16' || s === '9/16') return '9:16';
  if (s === '16:9' || s === '16/9') return '16:9';
  return '9:16';
}

function pickImageUrlFromUpstream(itemJson) {
  // 1) 你“准备图生视频参数-sora”里写的 requestBody.input.image_urls
  const u1 = itemJson?.requestBody?.input?.image_urls?.[0];
  if (u1) return safe(u1);

  // 2) 你也可以在“准备图生视频参数-sora”里直接输出 imageUrl 字段
  const u2 = itemJson?.imageUrl;
  if (u2) return safe(u2);

  // 3) 增加 try-catch 容错：防止未传图时，节点未执行导致报错
  try {
    const u3 = $('获取图片链接').first().json?.body?.data?.tmp_download_urls?.[0]?.tmp_download_url;
    if (u3) return safe(u3);
  } catch (e) {
    // 节点未执行时会进入这里，直接忽略即可
  }

  return '';
}

// ---- 必填上下文 ----
const record_id = safe(payload.record_id);
const app_token = safe(payload.app_token);
const table_id = safe(payload.table_id);
const tenant_access_token = safe(payload.tenant_access_token);
const api_key = safe(payload.api_key);
const workflow_id_for_credits = safe(payload.workflow_id_for_credits);

if (!record_id || !app_token || !table_id || !tenant_access_token || !api_key || !workflow_id_for_credits) {
  throw new Error('子流程入口缺少必要字段（record_id/app_token/table_id/tenant_access_token/api_key/workflow_id_for_credits）');
}

// ---- prompt / model / aspect_ratio ----
const prompt = cleanPrompt(payload.prompt);
if (!prompt) throw new Error('prompt 为空');

const model = 'sora-2-all'; // 你没传才给默认
const aspect_ratio = normAspect(payload.aspect_ratio);

// ---- images（可选）----
const itemJson = $input.first().json || {};
const imageUrl = pickImageUrlFromUpstream(itemJson);
const images = imageUrl ? [imageUrl] : undefined;

// ---- 云雾请求体 ----
function toOrientation(aspect_ratio) {
  // 9:16 => portrait, 16:9 => landscape
  return aspect_ratio === '16:9' ? 'landscape' : 'portrait';
}

function toDuration(payload) {
  // 你现在 payload.n_frames = "15" ——参考请求里 duration=15
  // 所以直接把 n_frames 当 duration(秒) 用，优先 payload.duration
  const d = Number(payload.duration ?? payload.n_frames ?? 15);
  return Number.isFinite(d) && d > 0 ? d : 15;
}

function toSize(payload) {
  // 云雾示例：large
  const s = String(payload.size ?? 'large').trim().toLowerCase();
  // 保险起见只放你确认过的值；不确定就统一 large
  if (['small','medium','large'].includes(s)) return s;
  return 'large';
}

const orientation = toOrientation(aspect_ratio);
const duration = toDuration(payload);
const size = toSize(payload);

// watermark: 参考请求 watermark=false
const watermark = payload.watermark ?? false;

// private: 只有 sora-2 接口示例里出现，你需要就透传，不需要就别带
const priv = payload.private;

const requestBody = {
  model: 'sora-2-all',
  prompt,
  images: images ?? [],          // 云雾示例里允许空数组
  orientation,
  size,
  duration,
  watermark,
  ...(priv !== undefined ? { private: !!priv } : {})
};

return [{
  json: {
    requestBody,

    // 透传上下文（给后面写表 + 轮询用）
    record_id,
    app_token,
    table_id,
    tenant_access_token,
    api_key,
    workflow_id_for_credits,

    // 你原来有的子表定位，继续透传
    out_app_token: payload.out_app_token,
    out_table_id: payload.out_table_id,
    batch_id: payload.batch_id,
    child_record_id: payload.child_record_id,

    debug: {
      model_from_input: safe(payload.model),
      model_used: model,
      aspect_ratio,
      has_image: !!imageUrl,
      imageUrl
    }
  }
}];

const payload = $('子流程入口-sora').item.json.body || {};

const requestBody = {
  model: 'sora-2-text-to-video',
  input: {
    prompt: payload.prompt || '',
    aspect_ratio: payload.aspect_ratio || '9:16', // 允许 9:16，后面清洗节点会转 portrait/landscape
    n_frames: String(payload.n_frames || '10'),
    remove_watermark: true
  }
};

return {
  json: {
    requestBody,

    // 父表上下文（原有）
    record_id: payload.record_id,
    app_token: payload.app_token,
    table_id: payload.table_id,
    tenant_access_token: payload.tenant_access_token,
    workflow_id_for_credits: payload.workflow_id_for_credits,
    api_key: payload.api_key,

    // ✅ 子表定位（新增）
    out_app_token: payload.out_app_token,
    out_table_id: payload.out_table_id,

    // 可选预留
    batch_id: payload.batch_id,
    child_record_id: payload.child_record_id
  }
};

const res = $input.first().json || {};

// 云雾 create 返回 example: { id: "...", status: "pending", status_update_time: ... }
const id = res.id || res.data?.id;
const status = res.status || res.data?.status || 'unknown';

if (!id) {
  throw new Error(`创建任务失败，响应里没有 id：${JSON.stringify(res).slice(0, 500)}`);
}

return [{
  json: {
    task_id: id,
    status,
  }
}];

const payload = $('子流程入口-sora').first().json.body || {};
const wid = String(payload.workflow_id_for_credits || '').trim();

const map = {
  flow_farm_md:   'https://hooks.flowonn.com/webhook/sora_md_callbackV4',
  flow_farm_zy:   'https://hooks.flowonn.com/webhook/sora_zy_callbackV4',
  flow_farm_copy: 'https://hooks.flowonn.com/webhook/sora_copy_callbackV4',
};

// 没匹配就走默认（你也可以直接 throw，让它明确失败）
const webhook_url = map[wid] || 'https://hooks.flowonn.com/webhook/sora_zy_callbackV4';

return [{
  json: {
    ...$input.first().json,       // 保留 task_id / status
    webhook_url,
    workflow_id_for_credits: wid,
  }
}];
